import React, { useState } from "react";
import Header from "./Header";
import Footer from "./Footer";
import LeadInquiryModal from "./LeadInquiryModal";

interface SiteLayoutProps {
  children: React.ReactNode;
}

export default function SiteLayout({ children }: SiteLayoutProps) {
  const [inquiryOpen, setInquiryOpen] = useState(false);
  const [inquiryCategory, setInquiryCategory] = useState<string | undefined>();
  const [toast, setToast] = useState<{ message: string; type: "success" | "info" } | null>(null);

  const navigate = (page: "home" | "builder" | "contacts" | "legal") => {
    if (page === "home") window.location.href = "/";
    else if (page === "builder") window.location.href = "/#builder";
    else if (page === "contacts") window.location.href = "/#contacts";
    else if (page === "legal") window.location.href = "/#legal";
  };

  const scrollToSection = (id: string) => {
    window.location.href = `/#${id}`;
  };

  const showToast = (message: string, type: "success" | "info") => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 5000);
  };

  return (
    <div className="min-h-screen bg-[#0e0e0e] flex flex-col">
      <Header
        onOpenBooking={() => { window.location.href = "/#benefits"; }}
        onOpenInquiry={(cat) => { setInquiryCategory(cat); setInquiryOpen(true); }}
        onScrollToSection={scrollToSection}
        currentPage="home"
        onNavigate={navigate}
      />

      <main className="flex-1">
        {children}
      </main>

      <Footer onScrollToSection={scrollToSection} onNavigate={navigate} />

      <LeadInquiryModal
        isOpen={inquiryOpen}
        onClose={() => setInquiryOpen(false)}
        preFilledCategory={inquiryCategory}
        onNotify={showToast}
      />

      {toast && (
        <div className={`fixed bottom-6 right-6 z-[100] max-w-sm px-5 py-4 rounded-lg shadow-2xl text-sm font-sans flex items-start gap-3 transition-all ${
          toast.type === "success"
            ? "bg-emerald-900/95 border border-emerald-500/40 text-white"
            : "bg-[#1c1c1c] border border-white/10 text-white/90"
        }`}>
          <div className={`w-2 h-2 rounded-full shrink-0 mt-1.5 ${toast.type === "success" ? "bg-emerald-400" : "bg-[#ff8562]"}`} />
          <span>{toast.message}</span>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { ArrowRight, SlidersHorizontal, X } from "lucide-react";
import SiteLayout from "../components/SiteLayout";
import { FurnitureItem, Category } from "../types";

interface CatalogPageProps {
  onOpenInquiry?: (category?: string) => void;
}

export default function CatalogPage({ onOpenInquiry }: CatalogPageProps) {
  const [products, setProducts] = useState<FurnitureItem[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [activeCategory, setActiveCategory] = useState<string>("all");
  const [loading, setLoading] = useState(true);
  const [selectedProduct, setSelectedProduct] = useState<FurnitureItem | null>(null);

  useEffect(() => {
    setLoading(true);
    Promise.all([
      fetch("/api/products").then(r => r.json()),
      fetch("/api/categories?type=product").then(r => r.json()),
    ]).then(([prods, cats]) => {
      setProducts(Array.isArray(prods) ? prods : []);
      setCategories(Array.isArray(cats) ? cats : []);
    }).finally(() => setLoading(false));
  }, []);

  const getCategoryName = (id: string) => {
    const cat = categories.find(c => c.id === id);
    return cat ? cat.name : id;
  };

  const filtered = activeCategory === "all"
    ? products
    : products.filter(p => p.category === activeCategory);

  return (
    <SiteLayout>
      <div className="bg-[#0e0e0e] text-white">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 py-10 sm:py-16">

          {/* Title */}
          <div className="mb-10">
            <p className="text-[#ff8562] font-mono text-xs uppercase tracking-[0.25em] mb-2">Мебель на заказ</p>
            <h1 className="text-3xl sm:text-5xl font-serif font-medium text-white tracking-tight">
              Каталог мебели <span className="font-serif italic text-[#ff8562]">Аспекто</span>
            </h1>
            <p className="text-white/50 text-sm mt-3 max-w-xl font-sans">
              Изготавливаем по индивидуальным проектам — каждое изделие создаётся под размеры и пожелания конкретного заказчика.
            </p>
          </div>

          {/* Category filter */}
          <div className="flex flex-wrap items-center gap-2 mb-8">
            <div className="flex items-center gap-1.5 mr-2 text-white/40">
              <SlidersHorizontal className="w-3.5 h-3.5" />
              <span className="text-xs font-mono uppercase tracking-wider">Фильтр:</span>
            </div>
            <button
              onClick={() => setActiveCategory("all")}
              className={`px-4 py-1.5 text-xs rounded-full border transition-all font-mono cursor-pointer ${
                activeCategory === "all"
                  ? "bg-[#ff8562] border-[#ff8562] text-white"
                  : "border-white/20 text-white/60 hover:border-white/40 hover:text-white"
              }`}
            >
              Все ({products.length})
            </button>
            {categories.map(cat => {
              const count = products.filter(p => p.category === cat.id).length;
              return (
                <button
                  key={cat.id}
                  onClick={() => setActiveCategory(cat.id)}
                  className={`px-4 py-1.5 text-xs rounded-full border transition-all font-mono cursor-pointer ${
                    activeCategory === cat.id
                      ? "bg-[#ff8562] border-[#ff8562] text-white"
                      : "border-white/20 text-white/60 hover:border-white/40 hover:text-white"
                  }`}
                >
                  {cat.name} ({count})
                </button>
              );
            })}
          </div>

          {/* Product grid */}
          {loading ? (
            <div className="flex items-center justify-center py-32">
              <span className="w-8 h-8 border-2 border-[#ff8562]/30 border-t-[#ff8562] rounded-full animate-spin" />
            </div>
          ) : filtered.length === 0 ? (
            <div className="text-center py-32 text-white/30">
              <p className="text-lg font-serif">Товары не найдены</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {filtered.map(product => (
                <article
                  key={product.id}
                  onClick={() => setSelectedProduct(product)}
                  className="group bg-[#181818] border border-white/10 hover:border-[#ff8562]/30 rounded-lg overflow-hidden cursor-pointer transition-all duration-300"
